const toolContent = results.length > 0
  ? results.join('\n\n')
  : 'Nenhuma informação relevante encontrada na base de conhecimento.';

const messages = [
  ...promptData.messages,
  extr.assistantMessage,
  { role: 'tool', tool_call_id: extr.toolCallId, content: toolContent },
];

return [{
  json: {
    model: promptData.model ?? 'google/gemini-2.5-flash-preview',
    messages,
    temperature: 0.8,
  }
}];

const raw = $input.first().json.value;
const cfg = raw ? JSON.parse(raw) : {};
return [{ json: cfg }];

// Mapeia mensagens do Chatwoot para formato de histórico LLM
const raw = $input.first().json;
const msgs = raw.payload ?? [];
const payload = $('Desembalar Payload').first().json;

// IDs das mensagens do batch atual (a excluir do histórico para evitar duplicata)
const excludeIds = new Set((payload.currentMsgIds ?? []).map(String));

// Filtrar: apenas incoming (0) e outgoing (1), excluir activity (2) e mensagens do batch atual
const filtradas = msgs.filter(m =>
  (m.message_type === 0 || m.message_type === 1) &&
  !excludeIds.has(String(m.id))
);

// Pegar últimas 80 para deixar espaço para sistema e resposta
const recentes = filtradas.slice(-80);

function formatContent(m) {
  const attachments = m.attachments ?? [];
  const imageAtt = attachments.find(a => a.file_type === 'image');
  // Para mensagens de entrada com imagem: retornar multimodal
  if (imageAtt && m.message_type === 0) {
    return [
      ...(m.content ? [{ type: 'text', text: m.content }] : [{ type: 'text', text: 'imagem' }]),
      { type: 'image_url', image_url: { url: imageAtt.data_url } },
    ];
  }
  const audioAtt = attachments.find(a => a.file_type === 'audio');
  if (audioAtt) return '[mensagem de voz]';
  const fileAtt = attachments.find(a => a.file_type === 'file');
  if (fileAtt) return `[arquivo: ${fileAtt.file_name || 'documento'}]`;
  return m.content ?? '';
}

const historico = recentes
  .map(m => ({ role: m.message_type === 0 ? 'user' : 'assistant', content: formatContent(m) }))
  .filter(m => m.content && (typeof m.content !== 'string' || m.content.trim() !== ''));

return [{ json: { historico } }];

const msg = $('Desembalar Payload').first().json;
const audioUrl = msg.metadata?.url ?? '';
if (!audioUrl) throw new Error('Sem URL de áudio: ' + JSON.stringify(msg.metadata));

// got nativo: responseType 'buffer' retorna Node.js Buffer sem corrupção
const raw = await this.helpers.httpRequest({
  method: 'GET',
  url: audioUrl,
  responseType: 'buffer',
});

let base64;
if (Buffer.isBuffer(raw)) {
  base64 = raw.toString('base64');
} else if (raw && typeof raw === 'object' && raw.byteLength !== undefined) {
  base64 = Buffer.from(raw).toString('base64');
} else if (typeof raw === 'string') {
  base64 = Buffer.from(raw, 'binary').toString('base64');
} else {
  throw new Error('Tipo inesperado: ' + typeof raw + ' / ' + (raw?.constructor?.name ?? 'n/a'));
}

if (base64.length < 1000) {
  throw new Error('Base64 suspeito: len=' + base64.length + ' tipo=' + typeof raw);
}

// Gemini via OpenRouter: usa image_url com data URI (não input_audio)
// audio/ogg é o MIME suportado pelo Gemini para Opus/OGG
return [{
  json: {
    base64
  }
}];

