  userContentForHistory = textParts || '[imagem enviada]';
} else {
  userContentForHistory = typeof rawUserContent === 'string' ? rawUserContent : (promptData.conteudo || '');
}

// Histórico com timestamps
const novoHistorico = [
  ...historico,
  { role: 'user', content: userContentForHistory },
  { role: 'assistant', content: `[${tsAgora}] ${content}` },
].slice(-100);

const contexto = {
  instance: promptData.instance,
  telefone: promptData.telefone,
  remoteJid: promptData.remoteJid,
  historico: novoHistorico,
  businessId: promptData.businessId ?? '',
  conversation_id: promptData.conversation_id ?? '',
  account_id: promptData.account_id ?? '1',
};

return chunks.map((texto, i) => ({
  json: {
    chunk: texto,
    fullText: content,
    isLast: i === chunks.length - 1,
    respondWithAudio,
    contexto,
    instance: promptData.instance,
    remoteJid: promptData.remoteJid,
    delay: 800 + i * 600,
    conversation_id: promptData.conversation_id ?? '',
    account_id: promptData.account_id ?? '1',
  }
}));

const binaryData = $input.first().binary?.data;
if (!binaryData) throw new Error('TTS: sem dados de �udio na resposta');
const audioBase64 = binaryData.data;

const allChunks = $('Parsear Chunks').all();
const ctx = allChunks[allChunks.length - 1]?.json ?? {};

return [{
  json: {
    audioBase64,
    instance: ctx.instance,
    remoteJid: ctx.remoteJid,
    evolutionAudioUrl: `https://evolution.vendly.chat/message/sendWhatsAppAudio/${ctx.instance}`,
    evolutionAudioBody: { number: ctx.remoteJid, audio: audioBase64, encoding: true },
    contexto: ctx.contexto,
  }
}];

const item = $input.first().json;
const { instance, remoteJid, chunk, delay, conversation_id, account_id } = item;

return [{
  json: {
    ...item,
    presenceUrl: `https://evolution.vendly.chat/chat/sendPresence/${instance}`,
    presenceBody: {
      number: remoteJid,
      options: { delay: delay ?? 800, presence: 'composing', number: remoteJid },
    },
    chatwootUrl: `https://chatwoot.vendly.chat/api/v1/accounts/${account_id || '1'}/conversations/${conversation_id}/messages`,
    chatwootBody: { content: chunk, message_type: 'outgoing', private: false },
  }
}];

const item = $('Preparar Envio').first().json;
await new Promise(r => setTimeout(r, item.delay ?? 800));
return [{ json: item }];

const items = $input.all();
const last = items[items.length - 1]?.json ?? {};
return [{ json: { contexto: last.contexto } }];

